={{ (() => {
  const n = $node["LOOP: Save Current Task (static)1"];
  const id = (n && n.json && n.json.task && n.json.task.id) ? String(n.json.task.id) : "";

  const u = id.toUpperCase();
  if (u.startsWith("CHAR_")) return "character";
  if (u.startsWith("PROP_")) return "prop";
  if (u.startsWith("LOC_")) return "location";
  return "shot";
})() }}

parameters.jsCode:
const src = $node["Set Inputs3"].json;

function lines(s) {
  return (s || '').split(/\r?\n/).map(x => (x || '').trim()).filter(Boolean);
}

function toDriveId(raw) {
  raw = String(raw || '').trim();
  if (!raw) return '';

  // si ya parece un ID (sin slashes y razonablemente largo), lo dejamos
  if (!raw.includes('drive.google.com') && !raw.includes('/')) return raw;

  const m1 = raw.match(/[?&]id=([^&]+)/);
  const m2 = raw.match(/\/d\/([^/]+)/);
  const m3 = raw.match(/file\/d\/([^/]+)/);

  return (m1?.[1] || m2?.[1] || m3?.[1] || raw).trim();
}


const all = [
  ...lines(src.ref_character_urls),
  ...lines(src.ref_object_urls),
  ...lines(src.ref_location_urls),
];

const ids = [...new Set(all.map(toDriveId).filter(Boolean))].slice(0, 14);

return ids.map(id => ({ json: { drive_file_id: id } }));

const base = $node["Set Inputs3"].json;

function driveDirectUrl(idOrUrl) {
  const id = String(idOrUrl || '').trim();
  if (!id) return null;

  // si ya es URL y no es Drive, la pasamos
  if (id.startsWith('http') && !id.includes('drive.google.com')) return id;

  // si es URL de Drive, extrae el id como en el otro nodo
  let fileId = '';
  const m1 = id.match(/[?&]id=([^&]+)/);
  const m2 = id.match(/\/d\/([^/]+)/);
  const m3 = id.match(/file\/d\/([^/]+)/);
  if (m1) fileId = m1[1];
  else if (m2) fileId = m2[1];
  else if (m3) fileId = m3[1];
  else fileId = id; // asumir que ya es el id

  return `https://drive.google.com/uc?export=download&id=${fileId}`;
}

// OJO: en este nuevo mundo, "items" ya NO vienen de descargas binarias.
// Vienen del Expand step (ids o urls).
const image_urls = items
  .map(i => driveDirectUrl(i.json.drive_file_id))
  .filter(Boolean)
  .slice(0, 14);

return [{
  json: {
    prompt: base.prompt,
    image_urls,
    num_images: base.num_images || 1,
    aspect_ratio: base.aspect_ratio || '16:9',
    resolution: base.resolution || '1K',
    output_format: base.output_format || 'png'
  }
}];

const sd = $getWorkflowStaticData('global');
sd.renderfarm = sd.renderfarm || {};

console.log('INIT SD BEFORE:', JSON.stringify(sd.renderfarm));

sd.renderfarm[$execution.id] = {
	job_id: $json.job_id,
	defaults: $json.defaults || {},
	output_folder_id: $json.output_folder_id || '',
	started_at: new Date().toISOString(),
	current_task: null,
	outputs: {}
};

console.log('INIT SD AFTER:', JSON.stringify(sd.renderfarm));

return items;

const sd = $getWorkflowStaticData('global');
const run = sd.renderfarm?.[$execution.id];
if (!run) throw new Error('Run state missing');

const defaults = run.defaults || {};
const output_folder_id = run.output_folder_id || defaults.output_folder_id || '';

const tasks = ($json.tasks || []).map((t, idx) => {
  if (!t || typeof t !== 'object') throw new Error(`Task ${idx} is not an object`);
  const id = t.id || t.task_id || `T${String(idx+1).padStart(3,'0')}`;
  const kind = t.kind || t.type;
  if (!kind) throw new Error(`Task ${id} missing kind/type`);

  const phase = Number.isFinite(t.phase)
    ? t.phase
    : (kind.startsWith('t2i') ? 1 : (kind.startsWith('i2i') ? 2 : 3));

  const order = Number.isFinite(t.order) ? t.order : idx;

  return {
    id,
    kind,
    modelId: t.modelId || defaults.modelId || '',
    phase,
    order,
    prompt: t.prompt || '',
    negative_prompt: t.negative_prompt || defaults.negative_prompt || '',
    refs: t.refs || {},

    aspect_ratio: t.aspect_ratio || defaults.aspect_ratio || '16:9',
    resolution: t.resolution || defaults.resolution || '1K',
    output_format: t.output_format || defaults.output_format || 'png',
    num_images: t.num_images || defaults.num_images || 1,

    duration: t.duration || defaults.duration || '5',
    generate_audio: (typeof t.generate_audio === 'boolean') ? t.generate_audio : (defaults.generate_audio ?? true),

    output: {
      folder_id: t.output?.folder_id || output_folder_id,
      file_name: t.output?.file_name || `${run.job_id}_${id}`
    }
  };
});

tasks.sort((a,b) => (a.phase - b.phase) || (a.order - b.order));

return tasks.map(task => ({ json: { task } }));

const t = $json.task;
if (!t) throw new Error('Missing task');
if (!t.kind) throw new Error('Task missing kind');
if (!t.prompt || !String(t.prompt).trim()) throw new Error(`Task ${t.id} missing prompt`);

const kind = t.kind;

// resolved fields are expected AFTER the REFS resolver
const start = t.resolved?.start_image_url || t.resolved?.main_image_url;
const list = t.resolved?.image_urls || [];

// i2v (Kling 2.6 pro continuation) needs start frame
if (kind === 'i2v' && !start) {
  throw new Error(`Task ${t.id} (i2v) needs resolved.start_image_url (provide refs.start_image_url or refs.from_tasks that resolves to a start frame)`);
}

// i2i needs at least 1 reference image
if (kind === 'i2i' && (!Array.isArray(list) || list.length === 0)) {
  throw new Error(`Task ${t.id} (i2i) needs at least 1 reference image in resolved.image_urls`);
}

// r2i (Kling o1 multi-ref) needs at least 1 reference image
if (kind === 'r2v' && (!Array.isArray(list) || list.length === 0)) {
  throw new Error(`Task ${t.id} (r2i) needs at least 1 reference image in resolved.image_urls`);
}

return items;

const sd = $getWorkflowStaticData('global');
const run = sd.renderfarm?.[$execution.id];
if (!run) throw new Error('Run state missing');

const summary = {
  job_id: run.job_id,
  started_at: run.started_at,
  finished_at: new Date().toISOString(),
  outputs: run.outputs || {}
};

return [{ json: summary }];

