parameters.jsCode:
const byTask = new Map();

for (const item of items) {
  const { task, ref, url } = item.json || {};
  if (!task) continue;

  const key = task.id;

  // Asegurar que el task existe en el map aunque no tenga refs
  if (!byTask.has(key)) {
    const t = JSON.parse(JSON.stringify(task));
    if (!t.resolved) t.resolved = {};
    if (!Array.isArray(t.resolved.image_urls)) t.resolved.image_urls = [];
    if (t.resolved.start_image_url === undefined) t.resolved.start_image_url = null;
    if (t.resolved.end_image_url === undefined) t.resolved.end_image_url = null;
    if (t.resolved.main_image_url === undefined) t.resolved.main_image_url = null;
    byTask.set(key, t);
  }

  // Si no hay ref/url, es passthrough (proyecto desde cero)
  if (!ref || !url) continue;

  const t = byTask.get(key);
  if (ref.role === "image") t.resolved.image_urls.push(url);
  if (ref.role === "start") t.resolved.start_image_url = url;
  if (ref.role === "end") t.resolved.end_image_url = url;
}

const out = [];
for (const t of byTask.values()) {
  if (!t.resolved.start_image_url) t.resolved.start_image_url = t.resolved.image_urls[0] || null;
  if (!t.resolved.main_image_url)  t.resolved.main_image_url  = t.resolved.image_urls[0] || t.resolved.start_image_url || null;
  out.push({ json: { task: t } });
}

return out;

const task = $json.task;

// Si no hay refs (proyecto desde cero) o no viene ref, passthrough
if ($json.noRefs === true || !task || !$json.ref) {
  return { json: { task, noRefs: true } };
}

const ref = $json.ref;
const skipDrive = $json.skipDrive === true;

// Caso URL directa (no Drive)
if (skipDrive) {
  const url = ref.directUrl || ref.url || ref.downloadUrl || null;
  if (!url) throw new Error(`skipDrive=true but no URL for: ${ref.name || '(unnamed ref)'}`);
  return { json: { task, ref, fileId: null, fileName: ref.name || null, url } };
}

// Caso Drive (merge ya metió id+name)
const fileId = $json.id || $json.fileId || null;
const fileName = $json.name || $json.fileName || ref.name || null;

if (!fileId) throw new Error(`Drive file id not found after merge for: ${ref.name || '(unnamed ref)'}`);

const url = `https://drive.google.com/uc?export=download&id=${fileId}`;
return { json: { task, ref, fileId, fileName, url } };

const task = $json.task;
if (!task) throw new Error('Missing task');

const refs = task.refs || {};
const want = [];

// Recolectar refs SIN mutar nada
if (Array.isArray(refs.from_tasks)) {
  for (const r of refs.from_tasks) {
    if (typeof r === 'string' && r.trim()) {
      want.push({ role: 'image', raw: r.trim() });
    }
  }
}

if (Array.isArray(refs.image_urls)) {
  for (const r of refs.image_urls) {
    if (typeof r === 'string' && r.trim()) {
      want.push({ role: 'image', raw: r.trim() });
    }
  }
}

/**
 * NUEVO: refs.from_files
 * - Acepta strings (nombres de archivo o URLs)
 * - Acepta objetos opcionales: { role: "image|start|end", raw: "..." }
 */
if (Array.isArray(refs.from_files)) {
  for (const r of refs.from_files) {
    if (typeof r === 'string' && r.trim()) {
      want.push({ role: 'image', raw: r.trim() });
      continue;
    }
    if (r && typeof r === 'object') {
      const role = (typeof r.role === 'string' && r.role.trim()) ? r.role.trim() : 'image';
      const raw = (typeof r.raw === 'string' && r.raw.trim()) ? r.raw.trim() : '';
      if (raw) want.push({ role, raw });
    }
  }
}

if (typeof refs.start_image_url === 'string' && refs.start_image_url.trim()) {
  want.push({ role: 'start', raw: refs.start_image_url.trim() });
}

if (typeof refs.end_image_url === 'string' && refs.end_image_url.trim()) {
  want.push({ role: 'end', raw: refs.end_image_url.trim() });
}

// Helpers PUROS
const isUrl = s => /^https?:\/\//i.test(s);

function normalizeName(raw) {
  if (isUrl(raw)) return raw;
  if (/\.(png|jpg|jpeg|webp|mp4)$/i.test(raw)) return raw;
  return raw + '.png';
}

function foldersFor(name, cfg) {
  if (isUrl(name)) return [];
  if (name.startsWith('CHAR_')) return [cfg.cfg_t2i_characters_folder_id];
  if (name.startsWith('LOC_'))  return [cfg.cfg_t2i_locations_folder_id];
  if (name.startsWith('PROP_')) return [cfg.cfg_t2i_props_folder_id];
  if (/^SHOT_.*_SP\.png$/i.test(name)) return [cfg.cfg_t2i_shots_folder_id];
  if (/_I2I\.png$/i.test(name)) return [cfg.cfg_i2i_folder_id];
  if (/_I2V.*\.mp4$/i.test(name)) return [cfg.cfg_i2v_folder_id];
  return [
    cfg.cfg_t2i_characters_folder_id,
    cfg.cfg_t2i_locations_folder_id,
    cfg.cfg_t2i_props_folder_id,
    cfg.cfg_t2i_shots_folder_id,
    cfg.cfg_i2i_folder_id,
    cfg.cfg_i2v_folder_id,
  ].filter(Boolean);
}

function driveQuery(name, folders) {
  const safe = name.replace(/'/g, "\\'");
  if (!folders.length) return `name = '${safe}' and trashed = false`;
  const parents = folders.map(f => `'${f}' in parents`).join(' or ');
  return `name = '${safe}' and (${parents}) and trashed = false`;
}

// Leer CFG una vez
const cfg = $node['CFG: Drive Folder IDs (central)'].json;

// Fanout CORRECTO
const out = [];

for (const entry of want) {
  const raw = entry.raw;
  const role = entry.role;

  if (isUrl(raw)) {
    out.push({
      json: {
        task,
        ref: { role, name: raw, directUrl: raw },
        skipDrive: true
      }
    });
    continue;
  }

  const name = normalizeName(raw);
  const folders = foldersFor(name, cfg);
  const query = driveQuery(name, folders);

  out.push({
    json: {
      task,
      ref: {
        role,
        name,
        folders: [...folders],
        query
      },
      skipDrive: false
    }
  });
}

if (out.length === 0) {
  return [{ json: { task, noRefs: true } }];
}

return out;

