const base = $node["Set Inputs3"].json;

function driveDirectUrl(raw) {
  raw = String(raw || '').trim();
  if (!raw) return null;

  // si ya es URL no-Drive
  if (raw.startsWith('http') && !raw.includes('drive.google.com')) return raw;

  // extraer fileId de formatos típicos de Drive
  const m1 = raw.match(/[?&]id=([^&]+)/);
  const m2 = raw.match(/\/d\/([^/]+)/);
  const m3 = raw.match(/file\/d\/([^/]+)/);
  const fileId = (m1?.[1] || m2?.[1] || m3?.[1] || raw).trim();

  return `https://drive.google.com/uc?export=download&id=${fileId}`;
}

function normResolutionUpper(r) {
  const s = String(r || "1K").trim().toUpperCase();

  // soporta también entradas tipo "1k", "2k", "4k" y variantes raras
  if (s === "1K" || s === "2K" || s === "4K") return s;
  if (s === "1") return "1K";
  if (s === "2") return "2K";
  if (s === "4") return "4K";

  // fallback
  return "1K";
}

const urls = items
  .map(i => driveDirectUrl(i.json.drive_file_id || i.json.url || i.json.id))
  .filter(Boolean);

const base_image = urls[0];
const refs = urls.slice(1, 14);

if (!base_image) throw new Error("kling o3 i2i requires a base image");

return [{
  json: {
    prompt: base.prompt,
    image_urls: [base_image],
    elements: [{ reference_image_urls: refs }],

    // 👇 AQUÍ el fix
    resolution: normResolutionUpper(base.resolution),

    result_type: "single",
    num_images: base.num_images || 1,
    aspect_ratio: base.aspect_ratio || "auto",
    output_format: base.output_format || "png",
  }
}];

