const sd = $getWorkflowStaticData('global');
const run = sd.renderfarm?.[$execution.id];
if (!run) throw new Error('Run state missing (did you run from the same execution?)');

const task = run.current_task;
if (!task) throw new Error('current_task missing. Ensure PRE block runs before pipelines.');

// Google Drive upload node usually returns { id, name, ... }
const fileId = $json.id || $json.fileId || $json.data?.id || $json.file?.id;
const fileName = $json.name || $json.fileName || $json.data?.name || $json.file?.name || task.output?.file_name || `${run.job_id}_${task.id}`;

if (!fileId) {
  throw new Error('Could not detect Google Drive file id from previous node output.');
}

const downloadUrl = `https://drive.google.com/uc?export=download&id=${fileId}`;

run.outputs = run.outputs || {};
run.outputs[task.id] = {
  task_id: task.id,
  kind: task.kind,
  file_name: fileName,
  drive_file_id: fileId,
  drive_download_url: downloadUrl,
  saved_at: new Date().toISOString()
};

// --- CHECKPOINT PERSISTENTE POR job_id (para reanudar) ---
sd.renderfarm_jobs = sd.renderfarm_jobs || {};

sd.renderfarm_jobs[run.job_id] = {
  job_id: run.job_id,
  started_at: run.started_at,
  outputs: run.outputs,
  last_completed: {
    task_id: task.id,
    at: new Date().toISOString()
  }
};

// Clear current task (optional safety)
run.current_task = null;

return [{
  json: {
    ok: true,
    task_id: task.id,
    kind: task.kind,
    drive_file_id: fileId,
    drive_download_url: downloadUrl,
    file_name: fileName
  }
}];

