const txt = $json.manifest_text;
if (!txt || typeof txt !== 'string') throw new Error('manifest_text is missing');

let manifest;
try {
  manifest = JSON.parse(txt);
} catch (e) {
  throw new Error('Manifest is not valid JSON: ' + e.message);
}

if (!manifest || typeof manifest !== 'object') {
  throw new Error('Missing manifest JSON');
}
if (!Array.isArray(manifest.tasks)) {
  throw new Error('manifest.tasks must be an array');
}

const job_id = manifest.job_id || `job_${Date.now()}`;
const defaults = manifest.defaults || {};
const output_folder_id = manifest.output_folder_id || defaults.output_folder_id || '';

return [{
  json: {
    job_id,
    defaults,
    output_folder_id,
    tasks: manifest.tasks
  }
}];

function escDriveQuote(s) {
  return String(s).replace(/\'/g, "\\\'");
}

const out = [];

for (const item of items) {
  const task = item.json.task;
  if (!task) throw new Error('Missing $json.task');

  const kind = task.kind;
  const id = task.id;

  const cfg = {
    t2i: {
      character: item.json.cfg_t2i_characters_folder_id,
      prop: item.json.cfg_t2i_props_folder_id,
      location: item.json.cfg_t2i_locations_folder_id,
      shot: item.json.cfg_t2i_shots_folder_id,
    },
    i2i: item.json.cfg_i2i_folder_id,
    i2v: item.json.cfg_i2v_folder_id,
    freestyle: item.json.cfg_freestyle_folder_id,
  };

  const inferAssetType = () => {
    if (task.asset_type) return String(task.asset_type).toLowerCase();
    if (String(id).startsWith('CHAR_')) return 'character';
    if (String(id).startsWith('PROP_')) return 'prop';
    if (String(id).startsWith('LOC_')) return 'location';
    return 'shot';
  };

  let folderId;
  let fileName;

  // Fix literal expressions or missing IDs
  const isInvalid = (fid) => !fid || String(fid).includes('{{') || String(fid).length < 20;
  const fallbackId = cfg.freestyle || '1lU6FHOSDvatyHqBxAASZs-1Atn39ahuu';

  if (kind === 't2i') {
    const assetType = inferAssetType();
    folderId = cfg.t2i[assetType];

    if (isInvalid(folderId)) {
      folderId = fallbackId;
    }

    const ext = String(task.output_format || 'png').toLowerCase();

    const suffixMap = {
      character: '_character',
      prop: '_prop',
      location: '_location',
      shot: '_shot',
    };

    const base = task.output?.file_name || `${id}${suffixMap[assetType] || '_shot'}`;
    fileName = `${base}.${ext}`;
  }
  else if (kind === 'i2i') {
    folderId = cfg.i2i;
    if (isInvalid(folderId)) {
      folderId = fallbackId;
    }

    const base = task.output?.file_name || id;
    fileName = `${base}.png`;
  }
  else if (kind === 'i2v' || kind === 'r2v') {
    folderId = cfg.i2v;
    if (isInvalid(folderId)) {
      folderId = fallbackId;
    }

    const base = task.output?.file_name || id;
    fileName = `${base}.mp4`;
  }
  else {
    folderId = fallbackId;
    fileName = `${id}.bin`;
  }

  const query = `name = '${escDriveQuote(fileName)}' and '${folderId}' in parents and trashed = false`;

  out.push({
    json: {
      ...item.json,
      expected: { folderId, fileName },
      query,
    }
  });
}

return out;

const sd = $getWorkflowStaticData('global');
console.log('SAVE SD:', JSON.stringify(sd.renderfarm));
console.log('EXEC ID:', $execution.id);

const run = sd.renderfarm?.[$execution.id];
if (!run) throw new Error('Run state missing');
run.current_task = $json.task;
return items;

const input = $json;

function toDirectUrl(raw) {
  raw = String(raw || '').trim();
  if (!raw) return null;

  // Si NO es Drive, lo dejamos tal cual
  if (!raw.includes('drive.google.com')) return raw;

  // Extraer fileId de formatos típicos
  let fileId = '';

  const m1 = raw.match(/[?&]id=([^&]+)/);     // ...?id=FILEID
  const m2 = raw.match(/\/d\/([^/]+)/);     // /d/FILEID/
  const m3 = raw.match(/file\/d\/([^/]+)/); // file/d/FILEID/

  if (m1) fileId = m1[1];
  else if (m2) fileId = m2[1];
  else if (m3) fileId = m3[1];
  else fileId = raw; // por si te pasan directamente el ID

  fileId = String(fileId).trim();
  return `https://drive.google.com/uc?export=download&id=${fileId}`;
}

const startRaw = input.start_image_url || input.image_url;
const start = toDirectUrl(startRaw);
if (!start) throw new Error('Missing start_image_url');

const end = input.end_image_url ? toDirectUrl(input.end_image_url) : null;

return {
  json: {
    ...input,
    start_image_url: start,
    // mantener compatibilidad si alguien sigue leyendo image_url
    image_url: start,
    ...(end ? { end_image_url: end } : {})
  },
};

const input = $json;

const raw = String(input.image_url || '').trim();
if (!raw) throw new Error('Missing image_url');

// Si NO es Drive, lo dejamos tal cual
if (!raw.includes('drive.google.com')) {
  return { json: { ...input, image_url: raw } };
}

// Extraer fileId de formatos típicos
let fileId = '';

const m1 = raw.match(/[?&]id=([^&]+)/);     // ...?id=FILEID
const m2 = raw.match(/\/d\/([^/]+)/);       // /d/FILEID/
const m3 = raw.match(/file\/d\/([^/]+)/);   // file/d/FILEID/

if (m1) fileId = m1[1];
else if (m2) fileId = m2[1];
else if (m3) fileId = m3[1];
else fileId = raw; // por si te pasan directamente el ID

fileId = fileId.trim();

const direct = `https://drive.google.com/uc?export=download&id=${fileId}`;

return {
  json: {
    ...input,
    image_url: direct,
    drive_file_id: fileId,
  },
};

