const base = $node["Set Inputs3"].json;

function driveDirectUrl(raw) {
  raw = String(raw || '').trim();
  if (!raw) return null;

  // si ya es URL no-Drive
  if (raw.startsWith('http') && !raw.includes('drive.google.com')) return raw;

  // extraer fileId de formatos típicos de Drive
  const m1 = raw.match(/[?&]id=([^&]+)/);
  const m2 = raw.match(/\/d\/([^/]+)/);
  const m3 = raw.match(/file\/d\/([^/]+)/);
  const fileId = (m1?.[1] || m2?.[1] || m3?.[1] || raw).trim();

  return `https://drive.google.com/uc?export=download&id=${fileId}`;
}

const urls = items
  .map(i => driveDirectUrl(i.json.drive_file_id || i.json.url || i.json.id))
  .filter(Boolean);

const image_url = urls[0];                 // OBLIGATORIO
const reference_image_urls = urls.slice(1, 14);

