const list = items.map(i => i.json).filter(Boolean);
if (list.length === 0) throw new Error("No manifest found (name contains 'manifest')");

list.sort((a,b) => (Date.parse(b.modifiedTime || b.createdTime || '') || 0) - (Date.parse(a.modifiedTime || a.createdTime || '') || 0));
const mf = list[0];
if (!mf.id) throw new Error('Manifest has no id');

return [{ json: { manifestFileId: mf.id, manifestFileName: mf.name } }];

const b = items[0].binary;
if (!b) throw new Error('No binary from Drive download');

const key = Object.keys(b)[0];
if (!key) throw new Error('Binary payload empty');

const data = b[key]?.data;
if (!data) throw new Error('Binary data missing');

const text = Buffer.from(data, 'base64').toString('utf8');
if (!text || !text.trim()) throw new Error('Manifest file is empty');

return [{ json: { manifest_text: text } }];

const name = String(items[0].json?.name || '').toUpperCase();
const state = 'RUN';
return [{ json: { control_name: items[0].json?.name, control_state: state } }];

// items = [original, selector] en cualquier orden
const arr = items.map(i => i.json || {});

// original: el que tiene prompt/task
const original = arr.find(x => x.prompt || x.task) || arr[0] || {};
// selector: el que tiene name "T2I - ..."
const selector = arr.find(x => typeof x.name === 'string' && x.name.toUpperCase().includes('T2I -')) || {};

const base = { ...original };
const selectorName = String(selector.name || '').trim();

let cfg = 'kling_o3';
let key = '';

if (selectorName) {
  const idx = selectorName.toLowerCase().indexOf('t2i -');
  key = idx !== -1 ? selectorName.slice(idx + 5).trim() : selectorName;

  const k = key.toLowerCase();
  if (k.includes('flux')) cfg = 'flux-2-max';
  else if (k.includes('o3')) cfg = 'kling_o3';
  else if (k.includes('banana') || k.includes('nano')) cfg = 'banana';
  else if (k.includes('imagen4') || k.includes('image4') || (k.includes('fast') && k.includes('imagen'))) cfg = 'imagen4fast';
}

return [{
  json: {
    ...base,
    cfg_t2i_model: cfg,
    t2i_selector_name: selectorName || '(missing -> default kling_o3)',
    t2i_selector_key: key
  }
}];

