const body = $json.body || {};
const project = body.project || { title: "FREESTYLE_LAB" };
const task = body.task || {};

// Normaliza tareas individuales o multiples
const tasks = Array.isArray(body.tasks) ? body.tasks : (Object.keys(task).length > 0 ? [task] : []);

